The `TabBar` component provides a user interface for managing a list of tabs. It allows users to switch between tabs, close tabs (if more than one is open), and open new tabs.

**Key Exports/Functions/Props:**

*   **`TabBar` function:** The main React component.
    *   `tabs`: An array of `Tab` objects, each containing `id` and `label` properties.
    *   `activeTabId`: The ID of the currently active tab.
    *   `onSwitch`: A callback function invoked when a user clicks on a tab to switch to it. It receives the `id` of the clicked tab.
    *   `onClose`: A callback function invoked when a user clicks the close button on a tab or middle-clicks a tab. It receives the `id` of the tab to be closed.
    *   `onAdd`: A callback function invoked when the "New tab" button is clicked.

**Usage Example:**

```typescript
import React, { useState } from 'react';
import { TabBar } from './TabBar';
import type { Tab } from './types';

const App: React.FC = () => {
  const [tabs, setTabs] = useState<Tab[]>([{ id: '1', label: 'Tab 1' }]);
  const [activeTabId, setActiveTabId] = useState<string>('1');

  const handleSwitchTab = (id: string) => {
    setActiveTabId(id);
  };

  const handleCloseTab = (id: string) => {
    const newTabs = tabs.filter(tab => tab.id !== id);
    setTabs(newTabs);
    if (activeTabId === id && newTabs.length > 0) {
      setActiveTabId(newTabs[0].id); // Switch to the first remaining tab
    } else if (newTabs.length === 0) {
      // Handle case where all tabs are closed if necessary
    }
  };

  const handleAddTab = () => {
    const newId = String(tabs.length + 1);
    const newTab = { id: newId, label: `Tab ${newId}` };
    setTabs([...tabs, newTab]);
    setActiveTabId(newId);
  };

  return (
    <TabBar
      tabs={tabs}
      activeTabId={activeTabId}
      onSwitch={handleSwitchTab}
      onClose={handleCloseTab}
      onAdd={handleAddTab}
    />
  );
};

export default App;
```

